import React from 'react';

const GanttChart = ({ data, isAnimating = false, currentStep = 0, stepMode = false }) => {
  if (!data || data.length === 0) {
    return null;
  }

  const getProcessColor = (processId) => {
    const colors = [
      'bg-blue-500',
      'bg-green-500',
      'bg-yellow-500',
      'bg-red-500',
      'bg-purple-500',
      'bg-pink-500',
      'bg-indigo-500',
      'bg-cyan-500',
      'bg-orange-500',
      'bg-teal-500'
    ];

    const hash = processId.split('').reduce((acc, char) => acc + char.charCodeAt(0), 0);
    return colors[hash % colors.length];
  };

  const maxTime = Math.max(...data.map(d => d.endTime));
  const totalWidth = Math.max(800, maxTime * 50); // Minimum width of 800px

  return (
    <div className="gantt-chart">
      {/* Time scale */}
      <div className="flex mb-2 text-xs text-gray-600 dark:text-gray-400">
        {Array.from({ length: maxTime + 1 }, (_, i) => (
          <div
            key={i}
            className="flex-shrink-0"
            style={{ width: `${totalWidth / (maxTime + 1)}px` }}
          >
            {i}
          </div>
        ))}
      </div>

      {/* Gantt timeline */}
      <div className="gantt-timeline" style={{ width: `${totalWidth}px` }}>
        {data.map((item, index) => {
          const duration = item.endTime - item.startTime;
          const width = (duration / maxTime) * totalWidth;
          const left = (item.startTime / maxTime) * totalWidth;

          const isActive = stepMode && isAnimating && index === currentStep;
          const isCompleted = stepMode && isAnimating && index < currentStep;

          return (
            <div
              key={index}
              className={`process-block ${getProcessColor(item.processId)} text-white step-animation ${
                isActive ? 'active' : ''
              } ${isCompleted ? 'opacity-60' : ''}`}
              style={{
                position: 'absolute',
                left: `${left}px`,
                width: `${width}px`,
                minWidth: '40px'
              }}
            >
              <span className="font-bold">{item.processId}</span>
              <span className="process-time text-gray-600 dark:text-gray-400">
                {item.startTime}-{item.endTime}
              </span>
            </div>
          );
        })}
      </div>

      {/* Legend */}
      <div className="mt-4 flex flex-wrap gap-2">
        {Array.from(new Set(data.map(d => d.processId))).map(processId => (
          <div key={processId} className="flex items-center space-x-1">
            <div className={`w-4 h-4 rounded ${getProcessColor(processId)}`}></div>
            <span className="text-xs text-gray-700 dark:text-gray-300">{processId}</span>
          </div>
        ))}
      </div>

      {/* Step indicator */}
      {stepMode && isAnimating && (
        <div className="mt-4 text-center">
          <span className="text-sm text-gray-600 dark:text-gray-400">
            Step {currentStep + 1} of {data.length}
          </span>
        </div>
      )}
    </div>
  );
};

export default GanttChart;
